const raw = $input.item.json;
const paper = raw.body ?? raw;
const apiKey = $env.OPENAI_API_KEY;
const paperId = paper.paper_id || '';
const title = paper.title || '';
const paperText = (paper.paper_text || '').slice(0, 12000);

const data = await this.helpers.request({
  method: 'POST',
  uri: 'https://api.openai.com/v1/chat/completions',
  headers: { 'Authorization': 'Bearer ' + apiKey },
  body: {
    model: 'gpt-4.1-mini',
    temperature: 0.2,
    max_tokens: 1500,
    messages: [
      {
        role: 'system',
        content: 'You are a Reader agent. Read the following paper and produce a structured summary. Cover: Problem & Motivation, Proposed Method, Results, Claimed Contributions.'
      },
      {
        role: 'user',
        content: 'Paper:\n' + paperText
      }
    ]
  },
  json: true
});

const summary = data.choices[0].message.content;
return [{ json: { paper_id: paperId, title, paper_text: paperText, reader_summary: summary } }];

const ctx = $input.item.json;
const apiKey = $env.OPENAI_API_KEY;
const summary = ctx.reader_summary || '';

const userMsg = 'Paper summary:\n' + summary +
  '\n\nGenerate 12-15 specific critique points.' +
  '\n\nFor each point you MUST:' +
  '\n- Be concrete and specific, not generic' +
  '\n- Reference specific sections, tables, or claims from the paper' +
  '\n- Focus on ONE issue per point' +
  '\n\nCover ALL of these dimensions:' +
  '\n- Novelty: what prior work is missing or inadequately compared?' +
  '\n- Methodology: are there hidden assumptions, missing ablations, or design choices not justified?' +
  '\n- Evaluation: are baselines fair? are comparisons apples-to-apples? are metrics sufficient?' +
  '\n- Reproducibility: what implementation details are missing?' +
  '\n- Clarity: what is confusing or poorly explained in the paper?' +
  '\n- Limitations: what does the method fail to address or acknowledge?' +
  '\n- Generalisability: does it work beyond the tested settings?' +
  '\n\nIMPORTANT: Only critique what is actually in the paper.' +
  '\nDo NOT invent references, section numbers, or claims not explicitly stated.';

const data = await this.helpers.request({
  method: 'POST',
  uri: 'https://api.openai.com/v1/chat/completions',
  headers: { 'Authorization': 'Bearer ' + apiKey },
  body: {
    model: 'gpt-4.1-mini',
    temperature: 0.2,
    max_tokens: 2000,
    messages: [
      {
        role: 'system',
        content: 'You are a Critic agent reviewing an AI/ML research paper.'
      },
      {
        role: 'user',
        content: userMsg
      }
    ]
  },
  json: true
});

const critique = data.choices[0].message.content;
return [{ json: { ...ctx, critic_1_points: critique } }];

const ctx = $input.item.json;
const apiKey = $env.OPENAI_API_KEY;
const summary = ctx.reader_summary || '';
const critique = ctx.critic_1_points || '';

const userMsg = 'Paper summary:\n' + summary +
  '\n\nCritic response:\n' + critique +
  '\n\nFor each critique point:' +
  '\n1. Is it specific enough or too generic? Push for concrete details.' +
  '\n2. Is it supported by evidence from the paper?' +
  '\n3. What important issues did the Critic completely miss?' +
  '\n\nBe aggressive — a weak vague point is worse than no point.' +
  '\nExplicitly list 3-5 issues the Critic missed.' +
  '\n\nDo NOT suggest ethical implications or bias points unless' +
  '\nthe paper explicitly makes claims in these areas.';

const data = await this.helpers.request({
  method: 'POST',
  uri: 'https://api.openai.com/v1/chat/completions',
  headers: { 'Authorization': 'Bearer ' + apiKey },
  body: {
    model: 'gpt-4.1-mini',
    temperature: 0.2,
    max_tokens: 1500,
    messages: [
      {
        role: 'system',
        content: 'You are an Auditor agent. Your job is to make the Critic\'s review stronger.'
      },
      {
        role: 'user',
        content: userMsg
      }
    ]
  },
  json: true
});

const auditFeedback = data.choices[0].message.content;
return [{ json: { ...ctx, auditor_feedback: auditFeedback } }];

