const apiKey = $env.OPENAI_API_KEY;
const summary = ctx.reader_summary || '';
const critique = ctx.critic_1_points || '';
const auditFeedback = ctx.auditor_feedback || '';

const userMsg = 'Original paper summary:\n' + summary +
  '\n\nYour original critique:\n' + critique +
  '\n\nAuditor feedback:\n' + auditFeedback +
  '\n\nNow produce an improved critique that:' +
  '\n- Fixes all weak or vague points the Auditor flagged' +
  '\n- Adds the missing issues the Auditor identified' +
  '\n- Keeps all strong original points' +
  '\n- Generates 12-15 total points' +
  '\n\nFor each point you MUST:' +
  '\n- Be concrete and specific, not generic' +
  '\n- Reference specific sections, tables, or claims from the paper' +
  '\n- Focus on ONE issue per point' +
  '\n\nCover ALL of these dimensions:' +
  '\n- Novelty: what prior work is missing or inadequately compared?' +
  '\n- Methodology: are there hidden assumptions, missing ablations, or design choices not justified?' +
  '\n- Evaluation: are baselines fair? are comparisons apples-to-apples? are metrics sufficient?' +
  '\n- Reproducibility: what implementation details are missing?' +
  '\n- Clarity: what is confusing or poorly explained in the paper?' +
  '\n- Limitations: what does the method fail to address or acknowledge?' +
  '\n- Generalisability: does it work beyond the tested settings?';

const data = await this.helpers.request({
  method: 'POST',
  uri: 'https://api.openai.com/v1/chat/completions',
  headers: { 'Authorization': 'Bearer ' + apiKey },
  body: {
    model: 'gpt-4.1-mini',
    temperature: 0.2,
    max_tokens: 2000,
    messages: [
      {
        role: 'system',
        content: 'You are the Critic agent revising your review based on Auditor feedback.'
      },
      {
        role: 'user',
        content: userMsg
      }
    ]
  },
  json: true
});

const critic2Output = data.choices[0].message.content;
return [{ json: { ...ctx, critic_2_points: critic2Output } }];

const ctx = $input.item.json;
const apiKey = $env.OPENAI_API_KEY;
const summary = ctx.reader_summary || '';
const critic2Output = ctx.critic_2_points || '';

const systemPrompt = 'You are a Summariser agent. Consolidate the critique into a final structured review.' +
  ' Output ONLY valid JSON with these fields:' +
  ' summary (2-3 sentence paper summary),' +
  ' strengths (array of {point, evidence}),' +
  ' weaknesses (array of {point, evidence}),' +
  ' questions (array of {question, motivation}),' +
  ' scores ({correctness: int 1-5, novelty: int 1-5, recommendation: accept|borderline|reject, confidence: int 1-5}).' +
  ' No markdown code fences, no other text.';

const userMsg = 'Critic2 output:\n' + critic2Output + '\n\nReader summary:\n' + summary;

const data = await this.helpers.request({
  method: 'POST',
  uri: 'https://api.openai.com/v1/chat/completions',
  headers: { 'Authorization': 'Bearer ' + apiKey },
  body: {
    model: 'gpt-4.1-mini',
    temperature: 0.2,
    max_tokens: 2000,
    messages: [
      { role: 'system', content: systemPrompt },
      { role: 'user', content: userMsg }
    ]
  },
  json: true
});

let rawOutput = data.choices[0].message.content.trim();
if (rawOutput.startsWith('```')) {
  rawOutput = rawOutput.split('```')[1];
  if (rawOutput.startsWith('json')) rawOutput = rawOutput.slice(4);
  rawOutput = rawOutput.trim();
}

let structured;
try {
  structured = JSON.parse(rawOutput);
} catch(e) {
  structured = { summary: '', strengths: [], weaknesses: [], questions: [], scores: { correctness: 3, novelty: 3, recommendation: 'borderline', confidence: 2 }, raw: rawOutput };
}

const critiquePoints = {};
(structured.weaknesses || []).forEach((w, i) => {
  const idx = String(i + 1).padStart(3, '0');
  const text = typeof w === 'string' ? w : ((w.point || '') + (w.evidence ? '. ' + w.evidence : ''));
  critiquePoints['point_' + idx] = text;
});

return [{ json: {
  paper_id: ctx.paper_id,
  title: ctx.title,
  platform: 'n8n',
  model: 'gpt-4.1-mini',
  structured,
  critique_points: critiquePoints,
  transcript: {
    reader: ctx.reader_summary,
    critic_1: ctx.critic_1_points,
    auditor: ctx.auditor_feedback,
    critic_2: ctx.critic_2_points
  }
} }];
